-- Seed courses (approach A: one item per course, modules as sections) into the
-- Kurser category, sv/en/es. Skips items whose title already exists.
INSERT INTO public.training_items
  (category_id, title, title_en, title_es, body, body_en, body_es, sort_order, is_published)
SELECT cat.id, v.title, v.title_en, v.title_es, v.body, v.body_en, v.body_es, v.ord, true
FROM (VALUES
  ('Grundkurs: Sälj från A till Ö', 'Foundation course: Selling from A to Z', 'Curso base: Vender de la A a la Z', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Mål: "}, {"type": "text", "text": "Få en komplett bild av säljresan – från att hitta ett företag till ett påskrivet avtal och en trygg överlämning."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 1 – Säljprocessen i överblick"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "de sju stegen och varför ordningen spelar roll."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Säljprocessen går: prospektering, första kontakt, behovsanalys, förslag/offert, invändningar, avslut/avtal och överlämning. Hoppa inte över behovsanalysen – det är där affären avgörs."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "En affär som rusar till offert utan behovsanalys landar ofta i \"det är för dyrt\"."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Rita upp de sju stegen ur minnet."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 2 – Prospektering – hitta rätt företag"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "att hitta företag med ett tydligt digitalt behov."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Leta efter signaler: daterad sajt, dålig Google-ranking, ingen e-handel trots produkter, ett växande bolag. Notera alltid en konkret observation att öppna med."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Jag såg att ni inte syns på takläggare Göteborg\" – en konkret krok."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Hitta tre företag idag och skriv en observation om varje."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 3 – Behovsanalys"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "ställa frågor som blottar det verkliga behovet."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Lägg mest tid här. Ställ öppna frågor, lyssna mer än du pratar och bekräfta: \"Så om jag förstår dig rätt…\". Nu vet du exakt vilken lösning du ska föreslå."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Hur får ni in nya kunder idag?\" säger mer än \"Vill ni ha fler kunder?\"."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Skriv fem öppna frågor du kan ställa i nästa möte."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 4 – Pitch, avslut & överlämning"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "koppla förslaget till behovet och stänga lugnt."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Presentera bara det som löser det kunden berättade. Avsluta utan press – målet är ett avtal: \"Känns det rätt? Då sätter vi det på pränt.\" När avtalet är klart tar bygg-teamet över och kontaktar kunden."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Du sa att ni tappar jobb till konkurrenten – det här vänder det.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Öva en avslutsmening som inte känns påträngande."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Goal: "}, {"type": "text", "text": "Get a complete picture of the sales journey – from finding a company to a signed agreement and a smooth handover."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 1 – The sales process at a glance"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "the seven steps and why the order matters."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "The sales process goes: prospecting, first contact, needs analysis, proposal/quote, objections, close/agreement and handover. Don't skip the needs analysis – that's where the deal is decided."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "A deal that rushes to a quote without a needs analysis often ends in \"it's too expensive\"."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Sketch the seven steps from memory."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 2 – Prospecting – find the right companies"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to find companies with a clear digital need."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Look for signals: a dated site, poor Google ranking, no e-commerce despite products, a growing company. Always note one concrete observation to open with."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"I noticed you don't show up for roofer Gothenburg\" – a concrete hook."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Find three companies today and write one observation about each."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 3 – Needs analysis"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to ask questions that reveal the real need."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Spend most time here. Ask open questions, listen more than you talk and confirm: \"So if I understand you correctly…\". Now you know exactly which solution to propose."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"How do you get new customers today?\" says more than \"Do you want more customers?\"."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Write five open questions you can ask in your next meeting."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 4 – Pitch, close & handover"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to tie the proposal to the need and close calmly."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Present only what solves what the customer told you. Close without pressure – the goal is an agreement: \"Does this feel right? Then let's put it in writing.\" Once the agreement is set, the build team takes over and contacts the customer."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"You said you lose jobs to the competitor – this turns that around.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Practise a closing line that doesn't feel pushy."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Meta: "}, {"type": "text", "text": "Obtén una visión completa del recorrido de venta: desde encontrar una empresa hasta un acuerdo firmado y un traspaso fluido."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 1 – El proceso de ventas de un vistazo"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "los siete pasos y por qué importa el orden."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "El proceso de ventas es: prospección, primer contacto, análisis de necesidades, propuesta/presupuesto, objeciones, cierre/acuerdo y traspaso. No te saltes el análisis de necesidades: ahí se decide la venta."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "Una operación que corre al presupuesto sin análisis de necesidades suele acabar en \"es demasiado caro\"."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Dibuja los siete pasos de memoria."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 2 – Prospección – encuentra las empresas adecuadas"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a encontrar empresas con una necesidad digital clara."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Busca señales: web anticuada, mal posicionamiento en Google, sin e-commerce pese a tener productos, empresa en crecimiento. Anota siempre una observación concreta para abrir."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Vi que no aparecéis para instalador de tejados Gotemburgo\": un gancho concreto."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Encuentra tres empresas hoy y escribe una observación de cada una."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 3 – Análisis de necesidades"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a hacer preguntas que revelen la necesidad real."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Dedica aquí la mayor parte del tiempo. Haz preguntas abiertas, escucha más de lo que hablas y confirma: \"Si te entiendo bien…\". Ahora sabes qué solución proponer."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"¿Cómo conseguís clientes hoy?\" dice más que \"¿Queréis más clientes?\"."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Escribe cinco preguntas abiertas para tu próxima reunión."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 4 – Pitch, cierre y traspaso"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a conectar la propuesta con la necesidad y cerrar con calma."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Presenta solo lo que resuelve lo que el cliente te contó. Cierra sin presión: el objetivo es un acuerdo: \"¿Te parece bien? Pues lo ponemos por escrito.\" Firmado el acuerdo, el equipo de construcción toma el relevo y contacta al cliente."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Dijiste que pierdes trabajos frente al competidor: esto lo revierte.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Practica una frase de cierre que no resulte insistente."}]}]}$j$::jsonb, 1),
  ('Behovsanalys & frågeteknik', 'Needs analysis & questioning technique', 'Análisis de necesidades y técnica de preguntas', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Mål: "}, {"type": "text", "text": "Bli den som ställer frågorna som öppnar affärer – och lyssnar så kunden själv sätter ord på behovet."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 1 – Öppna vs slutna frågor"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "när du ska använda vilken sorts fråga."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Slutna frågor ger ja/nej och stänger samtalet. Öppna frågor börjar med Hur, Vad, Varför eller Berätta och får kunden att prata. Tumregel: ca 80 % öppna frågor i behovsanalysen – slutna sparar du till att bekräfta och stänga."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Istället för \"Har ni problem med få besökare?\" → \"Hur får ni in nya kunder idag?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Skriv om tre slutna frågor du brukar ställa till öppna."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 2 – Hitta smärtan"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "gräva tills du hittar det verkliga behovet."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Folk köper för att lösa en smärta eller nå ett mål. Gräv vidare: \"Vad händer om det fortsätter så här?\" eller \"Vad kostar det er idag?\" Bekräfta: \"Så om jag förstår dig rätt…\". När kunden själv sätter ord på smärtan är halva affären gjord."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "Kund: \"Vår sajt är lite gammal.\" Du: \"Vad innebär det – tappar ni kunder till konkurrenter?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Lista tre följdfrågor som gräver djupare på \"vår hemsida är gammal\"."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 3 – Aktivt lyssnande"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "lyssna så kunden känner sig förstådd."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Prata mindre, pausa mer. Upprepa med egna ord, nicka och ställ följdfrågor på det kunden faktiskt säger. Anteckna nyckelord – du använder dem i pitchen."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Du nämnde att tid är er flaskhals – berätta mer om det.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Nästa möte: håll dig till att lyssna ca 70 % av tiden."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 4 – Koppla behov till lösning"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "översätta behovet till rätt paket."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "När du förstått behovet, matcha det mot en lösning och säg det med kundens egna ord. Föreslå en sak som löser deras största problem – inte hela katalogen."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Du vill ha fler förfrågningar utan att lägga tid – då är hemsida + SEO rätt start.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Para ihop tre vanliga behov med rätt paket."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Goal: "}, {"type": "text", "text": "Become the one who asks the questions that open deals – and listens so the customer puts the need into words themselves."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 1 – Open vs closed questions"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "when to use which type of question."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Closed questions give yes/no and close the conversation. Open questions start with How, What, Why or Tell me and get the customer talking. Rule of thumb: about 80% open questions in the needs analysis – save closed ones to confirm and close."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "Instead of \"Do you have a problem with few visitors?\" → \"How do you get new customers today?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Rewrite three closed questions you usually ask into open ones."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 2 – Find the pain"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to dig until you find the real need."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "People buy to solve a pain or reach a goal. Dig further: \"What happens if it continues like this?\" or \"What does it cost you today?\" Confirm: \"So if I understand you correctly…\". When the customer puts the pain into words, half the deal is done."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "Customer: \"Our site is a bit old.\" You: \"What does that mean – are you losing customers to competitors?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "List three follow-up questions that dig deeper into \"our website is old\"."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 3 – Active listening"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to listen so the customer feels understood."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Talk less, pause more. Paraphrase, nod and ask follow-ups on what the customer actually says. Note keywords – you'll use them in the pitch."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"You mentioned time is your bottleneck – tell me more about that.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Next meeting: aim to listen about 70% of the time."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 4 – Link need to solution"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to translate the need into the right package."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Once you understand the need, match it to a solution and say it in the customer's own words. Propose one thing that solves their biggest problem – not the whole catalogue."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"You want more enquiries without spending time – then website + SEO is the right start.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Match three common needs with the right package."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Meta: "}, {"type": "text", "text": "Conviértete en quien hace las preguntas que abren ventas y escucha para que el cliente exprese la necesidad por sí mismo."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 1 – Preguntas abiertas vs cerradas"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "cuándo usar cada tipo de pregunta."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Las preguntas cerradas dan sí/no y cierran la conversación. Las abiertas empiezan con Cómo, Qué, Por qué o Cuéntame y hacen hablar al cliente. Regla general: un 80 % de preguntas abiertas en el análisis; las cerradas, para confirmar y cerrar."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "En vez de \"¿Tenéis problema con pocas visitas?\" → \"¿Cómo conseguís clientes hoy?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Reescribe en abiertas tres preguntas cerradas que sueles hacer."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 2 – Encuentra el dolor"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a indagar hasta encontrar la necesidad real."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "La gente compra para resolver un dolor o alcanzar una meta. Indaga más: \"¿Qué pasa si sigue así?\" o \"¿Cuánto os cuesta hoy?\" Confirma: \"Si te entiendo bien…\". Cuando el cliente pone el dolor en palabras, media venta está hecha."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "Cliente: \"Nuestra web es algo antigua.\" Tú: \"¿Qué implica eso? ¿Perdéis clientes frente a la competencia?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Enumera tres preguntas de seguimiento que profundicen en \"nuestra web es antigua\"."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 3 – Escucha activa"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a escuchar para que el cliente se sienta comprendido."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Habla menos, haz más pausas. Parafrasea, asiente y haz preguntas sobre lo que el cliente dice de verdad. Anota palabras clave: las usarás en el pitch."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Mencionaste que el tiempo es vuestro cuello de botella; cuéntame más.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Próxima reunión: intenta escuchar alrededor del 70 % del tiempo."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 4 – Conecta necesidad y solución"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a traducir la necesidad al paquete adecuado."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Cuando entiendas la necesidad, conéctala con una solución y dilo con las palabras del cliente. Propón una cosa que resuelva su mayor problema, no todo el catálogo."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Queréis más solicitudes sin dedicar tiempo: entonces web + SEO es el inicio adecuado.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Empareja tres necesidades comunes con el paquete adecuado."}]}]}$j$::jsonb, 2),
  ('Invändningshantering & förhandling', 'Objection handling & negotiation', 'Manejo de objeciones y negociación', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Mål: "}, {"type": "text", "text": "Vänd ett nej till ett ja genom att bekräfta, vända till värde och ställa en fråga – och förhandla på värde, inte pris."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 1 – Metoden: bekräfta – vänd – fråga"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "en enkel struktur för varje invändning."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Ett: bekräfta känslan så kunden känner sig hörd. Två: vänd till värde eller en ny vinkel. Tre: avsluta med en fråga som för samtalet framåt. Bli aldrig defensiv."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Jag förstår att det är en investering (bekräfta). Men en extra kund i månaden betalar den (vänd). Vad är en ny kund värd för er? (fråga)\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Använd metoden på invändningen \"vi har redan en hemsida\"."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 2 – \"Det är för dyrt\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "hantera den vanligaste invändningen."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "\"För dyrt\" betyder oftast \"jag ser inte värdet än\". Vänd till avkastning och erbjud att börja i en mindre nivå. Sälj aldrig på pris – sälj på vad det ger."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Vad är en ny kund värd? Drar sajten in en extra kund i månaden har den betalat sig.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Skriv ditt eget svar på \"det är för dyrt\" i tre meningar."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 3 – Förhandla på värde, inte pris"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "hålla emot rabattjakt utan att tappa affären."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Sänk hellre omfånget än priset – ge inte bort värde gratis. Om du måste röra priset, be om något tillbaka: snabbare beslut, längre avtal eller en referens. Påminn om resultatet, inte kostnaden."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Jag kan börja i en mindre nivå istället för att sänka priset – då kommer ni igång nu.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Lista tre saker du kan be om i utbyte mot en rabatt."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Modul 4 – När du ska boka möte istället"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Det här lär du dig: "}, {"type": "text", "text": "känna igen när invändningen bäst löses i ett möte."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Vissa invändningar som \"skicka info\" eller \"måste tänka på det\" är artiga avfärdningar. Behåll initiativet: föreslå en kort återkoppling eller ett möte istället för att släppa taget. Ett ja till ett möte är också ett ja."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Exempel: "}, {"type": "text", "text": "\"Jag skickar gärna – ska vi ta 15 minuter på fredag så blir det relevant?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Öva: "}, {"type": "text", "text": "Formulera en mötesfråga för \"skicka info så återkommer vi\"."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Goal: "}, {"type": "text", "text": "Turn a no into a yes by acknowledging, turning to value and asking a question – and negotiate on value, not price."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 1 – The method: acknowledge – turn – ask"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "a simple structure for every objection."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "One: acknowledge the feeling so the customer feels heard. Two: turn to value or a new angle. Three: end with a question that moves the conversation forward. Never get defensive."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"I understand it's an investment (acknowledge). But one extra customer a month pays for it (turn). What is a new customer worth to you? (ask)\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Apply the method to the objection \"we already have a website\"."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 2 – \"It's too expensive\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to handle the most common objection."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "\"Too expensive\" usually means \"I don't see the value yet\". Turn to return and offer to start at a smaller level. Never sell on price – sell on what it delivers."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"What is a new customer worth? If the site brings in one extra a month, it's paid for itself.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Write your own three-sentence answer to \"it's too expensive\"."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 3 – Negotiate on value, not price"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to resist discount-hunting without losing the deal."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Lower the scope rather than the price – don't give value away for free. If you must move on price, ask for something back: a faster decision, a longer contract or a referral. Remind them of the result, not the cost."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"I can start at a smaller level instead of cutting the price – that way you get going now.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "List three things you can ask for in exchange for a discount."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Module 4 – When to book a meeting instead"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What you'll learn: "}, {"type": "text", "text": "to recognise when an objection is best solved in a meeting."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Some objections like \"send info\" or \"need to think about it\" are polite brush-offs. Keep the initiative: propose a short follow-up or a meeting instead of letting go. A yes to a meeting is also a yes."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Example: "}, {"type": "text", "text": "\"Happy to send it – shall we take 15 minutes on Friday so it's relevant?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practice: "}, {"type": "text", "text": "Phrase a meeting question for \"send info and we'll get back to you\"."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Meta: "}, {"type": "text", "text": "Convierte un no en un sí: reconoce, lleva al valor y haz una pregunta; y negocia sobre el valor, no el precio."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 1 – El método: reconoce – gira – pregunta"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "una estructura simple para cada objeción."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Uno: reconoce la emoción para que el cliente se sienta escuchado. Dos: gira hacia el valor o un nuevo ángulo. Tres: termina con una pregunta que avance la conversación. Nunca te pongas a la defensiva."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Entiendo que es una inversión (reconoce). Pero un cliente extra al mes la paga (gira). ¿Cuánto vale un cliente nuevo para ti? (pregunta)\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Aplica el método a la objeción \"ya tenemos una web\"."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 2 – \"Es demasiado caro\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a manejar la objeción más común."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "\"Demasiado caro\" suele significar \"aún no veo el valor\". Gira hacia el retorno y ofrece empezar con un nivel menor. Nunca vendas por precio: vende por lo que aporta."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"¿Cuánto vale un cliente nuevo? Si la web trae uno extra al mes, ya se paga sola.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Escribe tu propia respuesta a \"es demasiado caro\" en tres frases."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 3 – Negocia sobre valor, no precio"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a resistir la caza de descuentos sin perder la venta."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Reduce el alcance antes que el precio: no regales valor. Si debes tocar el precio, pide algo a cambio: una decisión más rápida, un contrato más largo o una referencia. Recuerda el resultado, no el coste."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Puedo empezar con un nivel menor en vez de bajar el precio: así arrancáis ya.\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Enumera tres cosas que puedes pedir a cambio de un descuento."}]}, {"type": "heading", "attrs": {"level": 3}, "content": [{"type": "text", "text": "Módulo 4 – Cuándo agendar una reunión en su lugar"}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué aprenderás: "}, {"type": "text", "text": "a reconocer cuándo una objeción se resuelve mejor en una reunión."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Material: "}, {"type": "text", "text": "Algunas objeciones como \"envía info\" o \"tenemos que pensarlo\" son rechazos corteses. Mantén la iniciativa: propón un breve seguimiento o una reunión en lugar de soltar. Un sí a una reunión también es un sí."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Ejemplo: "}, {"type": "text", "text": "\"Te la envío con gusto: ¿15 minutos el viernes para que sea relevante?\""}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Practica: "}, {"type": "text", "text": "Formula una pregunta de reunión para \"envía info y os contactamos\"."}]}]}$j$::jsonb, 3)
) AS v(title, title_en, title_es, body, body_en, body_es, ord)
JOIN public.training_categories cat ON cat.slug = 'kurser'
WHERE NOT EXISTS (
  SELECT 1 FROM public.training_items ti
  WHERE ti.category_id = cat.id AND ti.title = v.title
);
